// hasActiveFilters reports whether any chip-controllable filter dimension is
// currently applied. Search is intentionally excluded -- it has its own input
// above the chip row and is not represented as a removable chip, so counting
// it would show an active-filter badge / clear-all affordance with nothing
// individually removable (CR feedback on PR #1653).
func hasActiveFilters(data ActionQueueData) bool {
	return dashboardActiveFilterCount(data) > 0
}

// triFilterCount returns the number of active (include + exclude) values in a
// single tri-state filter dimension.
func triFilterCount(f rule.TriFilter) int {
	return len(f.Include) + len(f.Exclude)
}

// dashboardActiveFilterCount returns the number of distinct chip-controllable
// filter dimensions applied. Search is intentionally excluded from the count
// (see hasActiveFilters) so the count, the badge, and the visible chips stay
// aligned: every counted dimension has a corresponding chip the user can
// dismiss individually.
func dashboardActiveFilterCount(data ActionQueueData) int {
	// Tri-state: every included or excluded value across all five dimensions is
	// one removable chip, so each counts toward the badge total.
	return triFilterCount(data.SeverityFilter) +
		triFilterCount(data.CategoryFilter) +
		triFilterCount(data.LibraryFilter) +
		triFilterCount(data.RuleFilter) +
		triFilterCount(data.FixableFilter)
}

// libraryNameByID returns a library's name, or its ID when the library is
// unknown (e.g. deleted but violations still reference it).
func libraryNameByID(libs []library.Library, id string) string {
	for _, l := range libs {
		if l.ID == id {
			return l.Name
		}
	}
	return id
}

// ruleNameByID returns a rule's display name from the rule count slice, or
// the rule ID when no matching entry exists (e.g. disabled rule).
func ruleNameByID(counts []rule.RuleViolationCount, id string) string {
	for _, rc := range counts {
		if rc.RuleID == id {
			return rc.RuleName
		}
	}
	return id
}

// fixableLabel returns a human-readable label for the Fixable filter value.
func fixableLabel(ctx context.Context, value string) string {
	switch value {
	case "yes":
		return t(ctx, "dashboard.filter.fixable_yes")
	case "no":
		return t(ctx, "dashboard.filter.fixable_no")
	default:
		return value
	}
}

// severityLabel returns a human-readable label for a severity value.
func severityLabel(ctx context.Context, value string) string {
	switch value {
	case "error":
		return t(ctx, "common.severity_error")
	case "warning":
		return t(ctx, "common.severity_warning")
	case "info":
		return t(ctx, "common.severity_info")
	default:
		return value
	}
}

